import React, { useState } from 'react';
import CadastroCliente from './components/CadastroCliente';
import ListaClientes from './components/ListaClientes';
import MenuLateral from './components/MenuLateral';


function App() {
  const [atualizar, setAtualizar] = useState(0);
  return (
    <div style={{ display: 'flex' }}>
      <MenuLateral />
      <div style={{ maxWidth: '1200px', margin: '0 auto', padding: '2rem', marginLeft: 200, flex: 1 }}>
        <h1 style={{ textAlign: 'center', color: '#153a6b' }}>DOC PROVEDOR</h1>
        <CadastroCliente onClienteCadastrado={() => setAtualizar(a => a + 1)} />
        <ListaClientes atualizar={atualizar} />
      </div>
    </div>
  );
}

export default App;
